args.sparql:
SELECT ?game ?margin WHERE { {
 ?game wdt:P31 wd:Q538203 ;
       wdt:P710 wd:Q650840 ;
       wdt:P710 wd:Q334634 ;
       wdt:P3450 ?series .
 ?series wdt:P361 wd:Q1363275 .
 ?game p:P710 [
   ps:P710 wd:Q650840 ;
   pq:P1120 ?score1
 ] ;
    p:P710 [
   ps:P710 wd:Q334634 ;
   pq:P1120 ?score2
 ] .
 }
 FILTER(ISNUMERIC(?score1) && ISNUMERIC(?score2))
 BIND(ABS(xsd:integer(?score1) - xsd:integer(?score2)) AS ?margin)
}
ORDER BY DESC(?margin)
LIMIT 1

SELECT ?game ?margin WHERE {
  ?game wdt:P31 wd:Q538203 ;
        wdt:P361 ?series .
  ?series wdt:P179 wd:Q1363275 .

  ?game p:P710 ?dodgersStmt .
  ?dodgersStmt ps:P710 wd:Q334634 ;
              pq:P1110 ?dodgersScore .

  ?game p:P710 ?philliesStmt .
  ?philliesStmt ps:P710 wd:Q650840 ;
             pq:P1110 ?philliesScore .

  FILTER(xsd:integer(?dodgersScore) >= 0 && xsd:integer(?philliesScore) >= 0)
  BIND(ABS(xsd:integer(?dodgersScore) - xsd:integer(?philliesScore)) AS ?margin)
}
ORDER BY DESC(?margin)
LIMIT 1

SELECT ?game ?margin WHERE {
  ?game wdt:P31 wd:Q538203 ; # sports event
        wdt:P361 ?series .
  ?series wdt:P179 wd:Q1363275 .

  { /* Dodgers home, Phillies away */
    ?game wdt:P1445 wd:Q334634 ;
          wdt:P1446 wd:Q650840 ;
          wdt:P2087 ?dodgersScore ;
          wdt:P2088 ?philliesScore .
  } UNION {
    /* Phillies home, Dodgers away */
    ?game wdt:P1445 wd:Q650840 ;
          wdt:P1446 wd:Q334634 ;
          wdt:P2087 ?philliesScore ;
          wdt:P2088 ?dodgersScore .
  }

  FILTER(isNumeric(?dodgersScore) && isNumeric(?philliesScore))
  BIND(ABS(xsd:integer(?dodgersScore) - xsd:integer(?philliesScore)) AS ?margin)
}
ORDER BY DESC(?margin)
LIMIT 1

